kubectl patch statefulset es -n elasticsearch --type=strategic-merge -p '{
  "spec": {
    "template": {
      "spec": {
        "volumes": [
          {"name": "es-logs", "emptyDir": {}},
          {"name": "log4j2-override", "configMap": {"name": "es-log4j2"}},
          {"name": "metricbeat-config", "configMap": {"name": "metricbeat-config"}},
          {"name": "filebeat-config", "configMap": {"name": "filebeat-config"}}
        ],
        "containers": [
          {
            "name": "elasticsearch",
            "volumeMounts": [
              {"name": "es-logs", "mountPath": "/usr/share/elasticsearch/logs"},
              {"name": "log4j2-override", "mountPath": "/usr/share/elasticsearch/config/log4j2.properties", "subPath": "log4j2.properties"}
            ]
          },
          {
            "name": "metricbeat",
            "image": "docker.elastic.co/beats/metricbeat:7.17.9",
            "args": ["-c", "/etc/metricbeat/metricbeat.yml", "-e", "--strict.perms=false"],
            "env": [
              {"name": "ELASTIC_USERNAME", "value": "elastic"},
              {"name": "ELASTIC_PASSWORD", "valueFrom": {"secretKeyRef": {"name": "elastic-password", "key": "password"}}}
            ],
            "volumeMounts": [
              {"name": "metricbeat-config", "mountPath": "/etc/metricbeat/metricbeat.yml", "subPath": "metricbeat.yml"},
              {"name": "certs", "mountPath": "/certs", "readOnly": true}
            ],
            "resources": {"limits": {"cpu": "200m", "memory": "256Mi"}, "requests": {"cpu": "100m", "memory": "128Mi"}}
          },
          {
            "name": "filebeat",
            "image": "docker.elastic.co/beats/filebeat:7.17.9",
            "args": ["-c", "/etc/filebeat/filebeat.yml", "-e", "--strict.perms=false"],
            "volumeMounts": [
              {"name": "filebeat-config", "mountPath": "/etc/filebeat/filebeat.yml", "subPath": "filebeat.yml"},
              {"name": "es-logs", "mountPath": "/es-logs", "readOnly": true}
            ],
            "resources": {"limits": {"cpu": "200m", "memory": "256Mi"}, "requests": {"cpu": "100m", "memory": "128Mi"}}
          }
        ]
      }
    }
  }
}' 2>&1

